struct MaxThenMinHost {
    calls: u32,
}

impl ShellHost for MaxThenMinHost {
    fn subshell_end(&mut self) -> Option<i32> {
        self.calls += 1;
        match self.calls {
            1 => Some(i32::MAX),
            2 => Some(i32::MIN),
            _ => None,
        }
    }
}

