struct MinThenMaxHost {
    calls: u32,
}

impl ShellHost for MinThenMaxHost {
    fn subshell_end(&mut self) -> Option<i32> {
        self.calls += 1;
        match self.calls {
            1 => Some(i32::MIN),
            2 => Some(i32::MAX),
            _ => None,
        }
    }
}

