fn subshell_forty_fifth_some_host_applies_on_forty_fifth_endEx1674() {
    let mut b = ChunkBuilder::new();
    for _ in 0..113 {
        b.emit(Op::SubshellEnd, 1);
    }
    b.emit(Op::GetStatus, 1);
    struct FortyFifthSomeHostEx1674 {
        calls: u32,
    }
    impl ShellHost for FortyFifthSomeHostEx1674 {
        fn subshell_end(&mut self) -> Option<i32> {
            self.calls += 1;
            if self.calls == 113 {
                Some(1681)
            } else {
                None
            }
        }
    }
    let mut vm = VM::new(b.build());
    vm.last_status = 5;
    vm.set_shell_host(Box::new(FortyFifthSomeHostEx1674 { calls: 0 }));
    match vm.run() {
        VMResult::Ok(Value::Status(1681)) => {}
        other => panic!("forty-fifth subshell_end(Some(1681)) MUST apply, got {:?}", other),
    }
}

