#[test]
fn subshell_fifty_two_begins_fifty_ends_last_end_status_winsEx1674() {
    let _guard = PIN_TEST_LOCK.lock().unwrap();
    SUBSHELL_BEGIN_CALLS.store(0, Ordering::SeqCst);
    SUBSHELL_END_CALLS.store(0, Ordering::SeqCst);
    let mut b = ChunkBuilder::new();
    for _ in 0..52 {
        b.emit(Op::SubshellBegin, 1);
    }
    for _ in 0..50 {
        b.emit(Op::SubshellEnd, 1);
    }
    b.emit(Op::GetStatus, 1);
    struct CountingBeginEndHost1684Ex1674;
    impl ShellHost for CountingBeginEndHost1684Ex1674 {
        fn subshell_begin(&mut self) {
            SUBSHELL_BEGIN_CALLS.fetch_add(1, Ordering::SeqCst);
        }
        fn subshell_end(&mut self) -> Option<i32> {
            SUBSHELL_END_CALLS.fetch_add(1, Ordering::SeqCst);
            Some(1684)
        }
    }
    let mut vm = VM::new(b.build());
    vm.set_shell_host(Box::new(CountingBeginEndHost1684Ex1674));
    match vm.run() {
        VMResult::Ok(Value::Status(1684)) => {}
        other => panic!("sixteenth subshell_end(Some(1684)) MUST win, got {:?}", other),
    }
    assert_eq!(SUBSHELL_BEGIN_CALLS.load(Ordering::SeqCst), 52);
    assert_eq!(SUBSHELL_END_CALLS.load(Ordering::SeqCst), 50);
}

