#[test]
fn subshell_fifty_five_begins_fifty_three_ends_last_end_status_winsEx1755() {
    let _guard = PIN_TEST_LOCK.lock().unwrap();
    SUBSHELL_BEGIN_CALLS.store(0, Ordering::SeqCst);
    SUBSHELL_END_CALLS.store(0, Ordering::SeqCst);
    let mut b = ChunkBuilder::new();
    for _ in 0..55 {
        b.emit(Op::SubshellBegin, 1);
    }
    for _ in 0..53 {
        b.emit(Op::SubshellEnd, 1);
    }
    b.emit(Op::GetStatus, 1);
    struct CountingBeginEndHost1765Ex1755;
    impl ShellHost for CountingBeginEndHost1765Ex1755 {
        fn subshell_begin(&mut self) {
            SUBSHELL_BEGIN_CALLS.fetch_add(1, Ordering::SeqCst);
        }
        fn subshell_end(&mut self) -> Option<i32> {
            SUBSHELL_END_CALLS.fetch_add(1, Ordering::SeqCst);
            Some(1765)
        }
    }
    let mut vm = VM::new(b.build());
    vm.set_shell_host(Box::new(CountingBeginEndHost1765Ex1755));
    match vm.run() {
        VMResult::Ok(Value::Status(1765)) => {}
        other => panic!("seventeenth subshell_end(Some(1765)) MUST win, got {:?}", other),
    }
    assert_eq!(SUBSHELL_BEGIN_CALLS.load(Ordering::SeqCst), 55);
    assert_eq!(SUBSHELL_END_CALLS.load(Ordering::SeqCst), 53);
}

