#[test]
fn subshell_sixty_three_begins_sixty_one_ends_last_end_status_winsEx1979() {
    let _guard = PIN_TEST_LOCK.lock().unwrap();
    SUBSHELL_BEGIN_CALLS.store(0, Ordering::SeqCst);
    SUBSHELL_END_CALLS.store(0, Ordering::SeqCst);
    let mut b = ChunkBuilder::new();
    for _ in 0..63 {
        b.emit(Op::SubshellBegin, 1);
    }
    for _ in 0..61 {
        b.emit(Op::SubshellEnd, 1);
    }
    b.emit(Op::GetStatus, 1);
    struct CountingBeginEndHost1989Ex1979;
    impl ShellHost for CountingBeginEndHost1989Ex1979 {
        fn subshell_begin(&mut self) {
            SUBSHELL_BEGIN_CALLS.fetch_add(1, Ordering::SeqCst);
        }
        fn subshell_end(&mut self) -> Option<i32> {
            SUBSHELL_END_CALLS.fetch_add(1, Ordering::SeqCst);
            Some(1989)
        }
    }
    let mut vm = VM::new(b.build());
    vm.set_shell_host(Box::new(CountingBeginEndHost1989Ex1979));
    match vm.run() {
        VMResult::Ok(Value::Status(1989)) => {}
        other => panic!("seventeenth subshell_end(Some(1989)) MUST win, got {:?}", other),
    }
    assert_eq!(SUBSHELL_BEGIN_CALLS.load(Ordering::SeqCst), 63);
    assert_eq!(SUBSHELL_END_CALLS.load(Ordering::SeqCst), 61);
}

