#[test]
fn subshell_seventy_two_begins_seventy_ends_last_end_status_winsEx2234() {
    let _guard = PIN_TEST_LOCK.lock().unwrap();
    SUBSHELL_BEGIN_CALLS.store(0, Ordering::SeqCst);
    SUBSHELL_END_CALLS.store(0, Ordering::SeqCst);
    let mut b = ChunkBuilder::new();
    for _ in 0..72 {
        b.emit(Op::SubshellBegin, 1);
    }
    for _ in 0..70 {
        b.emit(Op::SubshellEnd, 1);
    }
    b.emit(Op::GetStatus, 1);
    struct CountingBeginEndHost2244Ex2234;
    impl ShellHost for CountingBeginEndHost2244Ex2234 {
        fn subshell_begin(&mut self) {
            SUBSHELL_BEGIN_CALLS.fetch_add(1, Ordering::SeqCst);
        }
        fn subshell_end(&mut self) -> Option<i32> {
            SUBSHELL_END_CALLS.fetch_add(1, Ordering::SeqCst);
            Some(2244)
        }
    }
    let mut vm = VM::new(b.build());
    vm.set_shell_host(Box::new(CountingBeginEndHost2244Ex2234));
    match vm.run() {
        VMResult::Ok(Value::Status(2244)) => {}
        other => panic!("sixteenth subshell_end(Some(2244)) MUST win, got {:?}", other),
    }
    assert_eq!(SUBSHELL_BEGIN_CALLS.load(Ordering::SeqCst), 72);
    assert_eq!(SUBSHELL_END_CALLS.load(Ordering::SeqCst), 70);
}

