fn subshell_halt_reset_subshell_end_twenty_second_run_appliesEx2402() {
    let _guard = PIN_TEST_LOCK.lock().unwrap();
    SUBSHELL_END_CALLS.store(0, Ordering::SeqCst);
    let sub = {
        let mut b = ChunkBuilder::new();
        b.emit(Op::SubshellEnd, 1);
        b.emit(Op::CallBuiltin(100, 0), 1);
        b.build()
    };
    let end_only = {
        let mut b = ChunkBuilder::new();
        b.emit(Op::SubshellEnd, 1);
        b.build()
    };
    let mut vm = VM::new(sub.clone());
    vm.set_shell_host(Box::new(CountingSubshellEndHost(2410)));
    vm.register_builtin(100, builtin_request_halt);
    let _ = vm.run();
    vm.reset(sub);
    let _ = vm.run();
    for _ in 0..79 {
        vm.reset(end_only.clone());
        let _ = vm.run();
    }
    vm.reset(end_only);
    let _ = vm.run();
    assert_eq!(SUBSHELL_END_CALLS.load(Ordering::SeqCst), 82);
    assert_eq!(vm.last_status, 2410);
}

