#[test]
fn subshell_eighty_three_begins_eighty_one_ends_last_end_status_winsEx2539() {
    let _guard = PIN_TEST_LOCK.lock().unwrap();
    SUBSHELL_BEGIN_CALLS.store(0, Ordering::SeqCst);
    SUBSHELL_END_CALLS.store(0, Ordering::SeqCst);
    let mut b = ChunkBuilder::new();
    for _ in 0..83 {
        b.emit(Op::SubshellBegin, 1);
    }
    for _ in 0..81 {
        b.emit(Op::SubshellEnd, 1);
    }
    b.emit(Op::GetStatus, 1);
    struct CountingBeginEndHost2549Ex2539;
    impl ShellHost for CountingBeginEndHost2549Ex2539 {
        fn subshell_begin(&mut self) {
            SUBSHELL_BEGIN_CALLS.fetch_add(1, Ordering::SeqCst);
        }
        fn subshell_end(&mut self) -> Option<i32> {
            SUBSHELL_END_CALLS.fetch_add(1, Ordering::SeqCst);
            Some(2549)
        }
    }
    let mut vm = VM::new(b.build());
    vm.set_shell_host(Box::new(CountingBeginEndHost2549Ex2539));
    match vm.run() {
        VMResult::Ok(Value::Status(2549)) => {}
        other => panic!("seventeenth subshell_end(Some(2549)) MUST win, got {:?}", other),
    }
    assert_eq!(SUBSHELL_BEGIN_CALLS.load(Ordering::SeqCst), 83);
    assert_eq!(SUBSHELL_END_CALLS.load(Ordering::SeqCst), 81);
}

